import React, { useEffect, useState } from 'react';

const ThemeToggle: React.FC = () => {
  const [isDark, setIsDark] = useState<boolean>(() => {
    if (typeof window !== 'undefined') {
      // Check if the class is present (from HTML) or default to true
      return document.documentElement.classList.contains('dark') || true;
    }
    return true;
  });

  useEffect(() => {
    if (isDark) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDark]);

  return (
    <button
      onClick={() => setIsDark(!isDark)}
      className="p-2 rounded-full bg-gray-200 dark:bg-gray-700 hover:bg-gray-300 dark:hover:bg-gray-600 transition-colors"
      aria-label="Toggle Dark Mode"
    >
      {isDark ? (
        // Sun Icon
        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5 text-yellow-500">
          <path strokeLinecap="round" strokeLinejoin="round" d="M12 3v2.25m6.364.386l-1.591 1.591M21 12h-2.25m-.386 6.364l-1.591-1.591M12 18.75V21m-4.773-4.227l-1.591 1.591M5.25 12H3m4.227-4.773L5.636 5.636M15.75 12a3.75 3.75 0 11-7.5 0 3.75 3.75 0 017.5 0z" />
        </svg>
      ) : (
        // Moon Icon
        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5 text-gray-700">
          <path strokeLinecap="round" strokeLinejoin="round" d="M21.752 15.002A9.718 9.718 0 0118 15.75c-5.385 0-9.75-4.365-9.75-9.75 0-1.33.266-2.597.748-3.752A9.753 9.753 0 003 11.25C3 16.635 7.365 21 12.75 21a9.753 9.753 0 009.002-5.998z" />
        </svg>
      )}
    </button>
  );
};

export default ThemeToggle;

import React, { useMemo } from 'react';
import { FormData, Gender, Mode, AspectRatio, ModelAI, ShotType } from '../types';
import {
  ETHNICITY_OPTIONS,
  AGE_RANGE_OPTIONS,
  HAIR_COLOR_OPTIONS,
  HAIR_MODEL_OPTIONS,
  OUTFIT_OPTIONS,
  BACKGROUND_OPTIONS,
  MODEL_OPTIONS,
  SHOT_TYPE_OPTIONS,
} from '../constants';

interface InputFormProps {
  formData: FormData;
  onChange: (data: FormData) => void;
  onGenerate: () => void;
  isLoading: boolean;
}

// Reusable Select Component with custom arrow
const SelectField = ({ 
  label, 
  value, 
  onChange, 
  options, 
  disabled = false 
}: { 
  label: string; 
  value: string; 
  onChange: (e: React.ChangeEvent<HTMLSelectElement>) => void; 
  options: { label: string; value: string }[];
  disabled?: boolean;
}) => (
  <div className="flex flex-col group">
    <label className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-2 ml-1">{label}</label>
    <div className="relative">
      <select
        value={value}
        onChange={onChange}
        disabled={disabled}
        className="w-full appearance-none bg-gray-50 dark:bg-gray-800/50 border border-gray-300 dark:border-gray-600 text-gray-900 dark:text-gray-100 rounded-xl px-4 py-3.5 pr-10 focus:outline-none focus:ring-2 focus:ring-primary/50 focus:border-primary transition-all font-medium text-sm disabled:opacity-50 disabled:cursor-not-allowed cursor-pointer hover:bg-white dark:hover:bg-gray-800 shadow-sm"
      >
        {options.map((opt) => (
          <option key={opt.value} value={opt.value} className="bg-white dark:bg-gray-900 text-gray-900 dark:text-gray-100 py-2">
            {opt.label}
          </option>
        ))}
      </select>
      {/* Custom Chevron Icon */}
      <div className="absolute inset-y-0 right-0 flex items-center px-4 pointer-events-none text-gray-500 dark:text-gray-400 group-hover:text-primary transition-colors">
        <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-5 h-5">
          <path fillRule="evenodd" d="M10 3a.75.75 0 01.55.24l3.25 3.5a.75.75 0 11-1.1 1.02L10 4.852 7.3 7.76a.75.75 0 01-1.1-1.02l3.25-3.5A.75.75 0 0110 3zm-3.76 9.2a.75.75 0 011.06.04l2.7 2.908 2.7-2.908a.75.75 0 111.1 1.02l-3.25 3.5a.75.75 0 01-1.1 0l-3.25-3.5a.75.75 0 01.04-1.06z" clipRule="evenodd" />
        </svg>
      </div>
    </div>
  </div>
);

const InputForm: React.FC<InputFormProps> = ({ formData, onChange, onGenerate, isLoading }) => {
  const handleChange = (field: keyof FormData, value: any) => {
    const newData = { ...formData, [field]: value };

    // Auto-correction/Validation logic
    if (field === 'gender') {
       // Check if current hair model is valid for new gender
       const validHairModels = HAIR_MODEL_OPTIONS.filter(opt => opt.type === 'unisex' || (value === 'Wanita' ? opt.type === 'f' : opt.type === 'm'));
       const currentModelValid = validHairModels.some(opt => opt.value === newData.hairModel);
       if (!currentModelValid) {
           newData.hairModel = validHairModels[0]?.value || '';
       }
    }

    onChange(newData);
  };

  const filteredHairModels = useMemo(() => {
    return HAIR_MODEL_OPTIONS.filter((option) => {
      if (option.type === 'unisex') return true;
      if (formData.gender === 'Wanita') return option.type === 'f';
      if (formData.gender === 'Pria') return option.type === 'm';
      return true;
    });
  }, [formData.gender]);

  const isHairSectionVisible = formData.mode === 'Non Hijab';

  return (
    <div className="bg-white dark:bg-gray-800 p-6 lg:p-8 rounded-2xl shadow-xl shadow-gray-200/50 dark:shadow-black/40 border border-gray-100 dark:border-gray-700 flex flex-col gap-6 h-full relative overflow-hidden">

      {/* Header */}
      <div className="relative z-10">
          <h2 className="text-2xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-gray-900 to-gray-600 dark:from-white dark:to-gray-400">
            Configuration
          </h2>
          <p className="text-gray-500 dark:text-gray-400 text-sm mt-1">Customize your influencer's look</p>
      </div>

      {/* Scrollable Content Area */}
      <div className="space-y-6 overflow-y-auto pr-2 custom-scrollbar -mr-2 pb-28">

        {/* Basic Info Group */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
            <SelectField 
                label="Gender" 
                value={formData.gender} 
                onChange={(e) => handleChange('gender', e.target.value as Gender)}
                options={[{label: 'Wanita', value: 'Wanita'}, {label: 'Pria', value: 'Pria'}]}
            />
             <SelectField 
                label="Mode" 
                value={formData.mode} 
                onChange={(e) => handleChange('mode', e.target.value as Mode)}
                options={[{label: 'Non Hijab', value: 'Non Hijab'}, {label: 'Hijab', value: 'Hijab'}]}
            />
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
             <SelectField 
                label="Tipe Shot" 
                value={formData.shotType} 
                onChange={(e) => handleChange('shotType', e.target.value as ShotType)}
                options={SHOT_TYPE_OPTIONS}
            />
             <SelectField 
                label="Rentang Usia" 
                value={formData.ageRange} 
                onChange={(e) => handleChange('ageRange', e.target.value)}
                options={AGE_RANGE_OPTIONS}
            />
        </div>

        <SelectField 
            label="Etnis" 
            value={formData.ethnicity} 
            onChange={(e) => handleChange('ethnicity', e.target.value)}
            options={ETHNICITY_OPTIONS}
        />

        {/* Hair Section (Conditional) */}
        {isHairSectionVisible && (
            <div className="p-5 bg-gray-50/80 dark:bg-gray-700/20 rounded-xl border border-dashed border-gray-200 dark:border-gray-600 space-y-5">
                <div className="flex items-center gap-2 mb-1">
                    <div className="w-1 h-4 bg-primary rounded-full"></div>
                    <span className="text-xs font-bold text-gray-500 uppercase tracking-wide">Hair Style</span>
                </div>
                <div className="grid grid-cols-1 gap-5">
                    <SelectField 
                        label="Warna Rambut" 
                        value={formData.hairColor} 
                        onChange={(e) => handleChange('hairColor', e.target.value)}
                        options={HAIR_COLOR_OPTIONS}
                    />
                    <SelectField 
                        label="Model Rambut" 
                        value={formData.hairModel} 
                        onChange={(e) => handleChange('hairModel', e.target.value)}
                        options={filteredHairModels}
                    />
                </div>
            </div>
        )}

        {/* Style Section */}
        <div className="space-y-5">
             <SelectField 
                label="Outfit" 
                value={formData.outfit} 
                onChange={(e) => handleChange('outfit', e.target.value)}
                options={OUTFIT_OPTIONS}
            />
             <SelectField 
                label="Studio Background" 
                value={formData.background} 
                onChange={(e) => handleChange('background', e.target.value)}
                options={BACKGROUND_OPTIONS}
            />
        </div>

        {/* Technical Section */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-5 pt-4 border-t border-gray-100 dark:border-gray-700">
             <SelectField 
                label="Aspect Ratio" 
                value={formData.aspectRatio} 
                onChange={(e) => handleChange('aspectRatio', e.target.value)}
                options={[{label: '9:16 (Portrait)', value: '9:16'}, {label: '16:9 (Landscape)', value: '16:9'}]}
            />
             <SelectField 
                label="Model AI" 
                value={formData.modelAI} 
                onChange={(e) => handleChange('modelAI', e.target.value)}
                options={MODEL_OPTIONS}
            />
        </div>

        {/* Details Section */}
        <div className="flex flex-col group">
             <label className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-2 ml-1">Detail Tambahan (Optional)</label>
             <textarea
                value={formData.details}
                onChange={(e) => handleChange('details', e.target.value)}
                placeholder="Misal: pakai kacamata hitam, anting emas..."
                className="w-full bg-gray-50 dark:bg-gray-800/50 border border-gray-300 dark:border-gray-600 text-gray-900 dark:text-gray-100 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-primary/50 focus:border-primary transition-all font-medium text-sm min-h-[100px] resize-y placeholder-gray-400 dark:placeholder-gray-500 shadow-sm"
            />
        </div>
      </div>

      {/* Floating Action Button with Gradient Fade */}
      <div className="absolute bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-white via-white/90 to-transparent dark:from-gray-800 dark:via-gray-800/90 dark:to-transparent z-20 pt-12">
        <button
          onClick={onGenerate}
          disabled={isLoading}
          className={`w-full py-4 rounded-xl font-bold text-white text-lg transition-all transform duration-200 shadow-lg shadow-primary/30 ${
            isLoading 
              ? 'bg-gray-400 cursor-not-allowed scale-[0.98]' 
              : 'bg-gradient-to-r from-primary to-secondary hover:shadow-xl hover:shadow-primary/40 hover:-translate-y-1 active:scale-[0.98]'
          }`}
        >
          {isLoading ? (
            <span className="flex items-center justify-center gap-3">
              <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
              Generating...
            </span>
          ) : (
            'Generate AI Influencer'
          )}
        </button>
      </div>

      <style>{`
        /* Custom Scrollbar */
        .custom-scrollbar::-webkit-scrollbar {
          width: 5px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: transparent;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background-color: rgba(156, 163, 175, 0.3);
          border-radius: 20px;
        }
        .dark .custom-scrollbar::-webkit-scrollbar-thumb {
          background-color: rgba(156, 163, 175, 0.2);
        }
      `}</style>
    </div>
  );
};

export default InputForm;

import React, { useState } from 'react';
import InputForm from './components/InputForm';
import OutputDisplay from './components/OutputDisplay';
import ThemeToggle from './components/ThemeToggle';
import { FormData, GenerationResult } from './types';
import { buildPrompts, generateImageUrl } from './services/promptService';
import { ETHNICITY_OPTIONS, AGE_RANGE_OPTIONS, HAIR_COLOR_OPTIONS, HAIR_MODEL_OPTIONS, OUTFIT_OPTIONS, BACKGROUND_OPTIONS } from './constants';

const App: React.FC = () => {
  const [formData, setFormData] = useState<FormData>({
    gender: 'Wanita',
    mode: 'Non Hijab',
    ethnicity: ETHNICITY_OPTIONS[0].value,
    ageRange: AGE_RANGE_OPTIONS[1].value, // 25an as default
    hairColor: HAIR_COLOR_OPTIONS[1].value, // Cokelat Tua
    hairModel: HAIR_MODEL_OPTIONS.find(o => o.type === 'f')?.value || '', // Default female hair
    outfit: OUTFIT_OPTIONS[0].value,
    background: BACKGROUND_OPTIONS[0].value,
    aspectRatio: '9:16',
    modelAI: 'zimage',
    shotType: 'Half-body',
    details: '',
  });

  const [isLoading, setIsLoading] = useState(false);
  const [result, setResult] = useState<GenerationResult | null>(null);

  const handleGenerate = async () => {
    setIsLoading(true);

    try {
      // 1. Build Prompts
      const { promptEn, promptId, promptLong } = buildPrompts(formData);

      // Determine which Pollinations model to use
      // Directly use the selected value from dropdown (zimage or imagen-4)
      const pollinationModel = formData.modelAI;
      const displayModelName = formData.modelAI === 'imagen-4' ? 'Google Imagen 4' : 'Z-Image Turbo';

      // 2. Generate Seeds
      const seedA = Math.floor(Math.random() * 1000000);
      const seedB = seedA + 1; // Distinct seed

      // 3. Construct URLs using Pollinations
      const urlA = generateImageUrl(promptEn, pollinationModel, formData.aspectRatio, seedA);
      const urlB = generateImageUrl(promptEn, pollinationModel, formData.aspectRatio, seedB);

      // 4. Update State
      setResult({
        images: [
          { url: urlA, seed: seedA, model: displayModelName },
          { url: urlB, seed: seedB, model: displayModelName },
        ],
        promptEn,
        promptId,
        promptLong,
      });

      // Simulate delay for UI polish (since URL generation is instant)
      setTimeout(() => {
          setIsLoading(false);
      }, 1500);

    } catch (error: any) {
      console.error("Error generating images:", error);

      const errorMessage = error.message || "Unknown error occurred";

      const errorDiv = document.createElement('div');
      errorDiv.className = "fixed bottom-5 right-5 bg-red-100 border-l-4 border-red-500 text-red-700 p-4 rounded shadow-lg z-50 max-w-md animate-bounce-in";
      errorDiv.innerHTML = `
        <p class="font-bold">Generation Failed</p>
        <p class="text-sm">${errorMessage}</p>
        <button class="absolute top-2 right-2 text-red-700 font-bold" onclick="this.parentElement.remove()">×</button>
      `;
      document.body.appendChild(errorDiv);
      setTimeout(() => errorDiv.remove(), 8000);

      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen transition-colors duration-200 flex flex-col font-sans">
      {/* Header */}
      <header className="sticky top-0 z-50 bg-white/80 dark:bg-gray-900/80 backdrop-blur-md border-b border-gray-200 dark:border-gray-700">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-gradient-to-tr from-primary to-secondary p-2 rounded-lg">
                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-5 h-5 text-white">
                    <path strokeLinecap="round" strokeLinejoin="round" d="M9.813 15.904L9 18.75l-.813-2.846a4.5 4.5 0 00-3.09-3.09L2.25 12l2.846-.813a4.5 4.5 0 003.09-3.09L9 5.25l.813 2.846a4.5 4.5 0 003.09 3.09L15.75 12l-2.846.813a4.5 4.5 0 00-3.09 3.09zM18.259 8.715L18 9.75l-.259-1.035a3.375 3.375 0 00-2.455-2.456L14.25 6l1.036-.259a3.375 3.375 0 002.455-2.456L18 2.25l.259 1.035a3.375 3.375 0 002.456 2.456L21.75 6l-1.035.259a3.375 3.375 0 00-2.456 2.456zM16.894 20.567L16.5 21.75l-.394-1.183a2.25 2.25 0 00-1.423-1.423L13.5 18.75l1.183-.394a2.25 2.25 0 001.423-1.423l.394-1.183.394 1.183a2.25 2.25 0 00-1.423 1.423z" />
                </svg>
            </div>
            <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-gray-900 to-gray-600 dark:from-white dark:to-gray-300">
              AI Influencer Maker
            </h1>
          </div>
          <ThemeToggle />
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-grow max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 w-full">
        <div className="flex flex-col lg:flex-row gap-8 items-start h-full">

          {/* Left Column: Input Form */}
          <div className="w-full lg:w-1/3 lg:sticky lg:top-24">
            <InputForm 
              formData={formData} 
              onChange={setFormData} 
              onGenerate={handleGenerate}
              isLoading={isLoading}
            />
          </div>

          {/* Right Column: Output */}
          <div className="w-full lg:w-2/3 min-h-[500px]">
            <OutputDisplay 
                result={result} 
                isLoading={isLoading} 
                aspectRatio={formData.aspectRatio}
            />
          </div>

        </div>
      </main>

      {/* Footer */}
      <footer className="bg-white dark:bg-gray-900 border-t border-gray-200 dark:border-gray-800 mt-12">
        <div className="max-w-7xl mx-auto px-4 py-6 sm:px-6 lg:px-8">
          <p className="text-center text-sm text-gray-500 dark:text-gray-400">
            Powered by Pollinations API • Built with React & Tailwind
          </p>
        </div>
      </footer>
    </div>
  );
};

export default App;

{
  "name": "AI Influencer Maker",
  "description": "Generate photorealistic AI influencer images with customizable attributes using the Pollinations API.",
  "requestFramePermissions": []
}

export type Gender = 'Female' | 'Male';
export type Mode = 'Hijab' | 'No Hijab';
export type AspectRatio = '9:16' | '16:9';
export type ModelAI = 'zimage' | 'imagen-4';
export type ShotType = 'Half-body' | 'Full-body';

export interface HairModelOption {
  label: string;
  value: string; // English token
  type: 'f' | 'm' | 'unisex';
}

export interface FormData {
  gender: Gender;
  mode: Mode;
  ethnicity: string;
  ageRange: string;
  hairColor: string;
  hairModel: string;
  outfit: string;
  background: string;
  aspectRatio: AspectRatio;
  modelAI: ModelAI;
  shotType: ShotType;
  details: string;
}

export interface GeneratedImage {
  url: string;
  seed: number;
  model: string;
}

export interface GenerationResult {
  images: [GeneratedImage, GeneratedImage];
  promptEn: string;
  promptId: string;
  promptLong: string;
}

export interface SelectOption {
  label: string;
  value: string; // English token or ID key
}

